const now = new Date().toISOString();

const systemManifest = {
  system_id: 'AI5R',
  kernel: 'OSA',
  architecture: 'Asset-Oriented Operating Platform',
  version: '1.0.0'
};

const registry = {
  registry_version: '1.0.0',
  assets: [
    { asset_id: 'OSA.KERNEL.GATEWAY.001', asset_type: 'kernel', status: 'active' },
    { asset_id: 'OSA.KERNEL.CREDENTIAL_VAULT.001', asset_type: 'kernel', status: 'active' },
    { asset_id: 'OSA.KERNEL.LOGGER.001', asset_type: 'kernel', status: 'active' },
    { asset_id: 'OSA.KERNEL.REGISTRY.001', asset_type: 'kernel', status: 'active' },
    { asset_id: 'OSA.KERNEL.HEALTH_MONITOR.001', asset_type: 'kernel', status: 'active' },
    { asset_id: 'AI5R.PLATFORM.MEMORY.001', asset_type: 'platform', status: 'active' },
    { asset_id: 'AI5R.PLATFORM.GIT.001', asset_type: 'platform', status: 'active' },
    { asset_id: 'AI5R.PLATFORM.ARTIFACT.001', asset_type: 'platform', status: 'active' }
  ]
};

const dependencyGraph = {
  'AI5R.PLATFORM.MEMORY.001': ['OSA.KERNEL.REGISTRY.001', 'OSA.KERNEL.LOGGER.001'],
  'AI5R.PLATFORM.GIT.001': ['OSA.KERNEL.GATEWAY.001', 'OSA.KERNEL.LOGGER.001'],
  'AI5R.PLATFORM.ARTIFACT.001': ['AI5R.PLATFORM.MEMORY.001', 'AI5R.PLATFORM.GIT.001']
};

const assetMap = Object.fromEntries(registry.assets.map(a => [a.asset_id, a]));
const modules = registry.assets.map(asset => ({
  asset_id: asset.asset_id,
  asset_type: asset.asset_type,
  status: asset.status,
  dependencies: dependencyGraph[asset.asset_id] || []
}));

const errors = [];
for (const mod of modules) {
  for (const dep of mod.dependencies) {
    if (!assetMap[dep]) errors.push(`Missing dependency ${dep} for ${mod.asset_id}`);
  }
}

return [{
  json: {
    success: errors.length === 0,
    service: 'OSA-REGISTRY-LOADER-001',
    status: errors.length ? 'DEGRADED' : 'READY',
    loaded_at: now,
    system_manifest: systemManifest,
    registry_version: registry.registry_version,
    modules_count: modules.length,
    modules,
    errors
  }
}];
